// ══════════════════════════════════════════════════════════════════════
// CONFIGURAÇÃO DO CLIENTE — edite aqui ao duplicar o workflow
// ══════════════════════════════════════════════════════════════════════
const CLIENT = {
  brand_slug: 'minha-marca',
  brand_name: 'Minha Marca',
  niche: 'finance',
  cta: 'Saiba mais',
  content_type: 'both',  // carousel | video | both
  creator: '',           // criador de referência (vazio = sem)
  duration: 15,          // duração do vídeo (seg)
};

// ══════════════════════════════════════════════════════════════════════
// BANCO DE TEMAS — a IA roda um tema por execução, em ordem circular
// ══════════════════════════════════════════════════════════════════════
const TEMAS = [
  'Como economizar dinheiro em 2025',
  '5 dicas para investir com pouco',
  'Os erros que destroem seu score de crédito',
  'Crédito pessoal: quando vale a pena?',
  'O segredo dos juros compostos',
  'Como sair das dívidas em 90 dias',
  'Guia rápido de educação financeira',
  'Cartão de crédito: inimigo ou aliado?',
];

// ── Rotação circular de temas ─────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
let idx = staticData.topicIndex || 0;
if (idx >= TEMAS.length) idx = 0;
const topic = TEMAS[idx];
staticData.topicIndex = idx + 1;

const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);

return {
  ...CLIENT,
  topic,
  topic_index: idx,
  total_topics: TEMAS.length,
  output_dir: `output/${CLIENT.brand_slug}_${ts}`,
  execution_id: ts,
};

const copy = $input.item.json;
const vars = $('⚙️ Config do Cliente + Rotação de Temas').item.json;

if (!copy.ok) {
  throw new Error('Erro ao gerar copy: ' + JSON.stringify(copy));
}

return {
  brand_slug: vars.brand_slug,
  brand_name: vars.brand_name,
  niche: vars.niche,
  output_dir: vars.output_dir,
  cta: vars.cta,
  content_type: vars.content_type,
  duration: vars.duration,
  topic: vars.topic,
  copy: {
    formula: copy.formula,
    headline_part1: copy.headline_part1,
    headline_part2: copy.headline_part2,
    caption: copy.caption,
    hashtags: copy.hashtags,
    image_query: copy.image_query,
    video_query: copy.video_query,
    compliance_flags: copy.compliance_flags
  },
  has_compliance_flags: (copy.compliance_flags ?? []).length > 0,
  compliance_summary: (copy.compliance_flags ?? []).join(' | ')
};

const vars = $('Montar payload').item.json;

let cover_path = null;
let video_path = null;
let slide_paths = [];
let drive_urls_carousel = [];
let drive_urls_video = [];

try {
  const carousel = $('🖼️ Renderizar Carrossel').item.json;
  if (carousel && carousel.ok) {
    cover_path = carousel.cover_path;
    slide_paths = carousel.slide_paths ?? [];
    drive_urls_carousel = carousel.drive_urls ?? [];
  }
} catch(e) {}

try {
  const video = $('🎬 Renderizar Vídeo').item.json;
  if (video && video.ok) {
    video_path = video.video_path;
    drive_urls_video = video.drive_urls ?? [];
  }
} catch(e) {}

return {
  brand_slug: vars.brand_slug,
  brand_name: vars.brand_name,
  niche: vars.niche,
  output_dir: vars.output_dir,
  topic: vars.topic,
  copy: vars.copy,
  cover_path,
  video_path,
  slide_paths,
  drive_urls: [...drive_urls_carousel, ...drive_urls_video],
  has_compliance_flags: vars.has_compliance_flags,
  compliance_summary: vars.compliance_summary
};

const vars = $('Consolidar resultados').item.json;

let ads_data = {};
try {
  const ads = $('📦 Gerar Pacote de Ads').item.json;
  if (ads && ads.ok) {
    ads_data = {
      google_copy: ads.google_copy,
      meta_copy: ads.meta_copy,
      report_path: ads.report_path
    };
  }
} catch(e) {}

const copy = vars.copy;

return {
  ok: true,
  brand: vars.brand_slug,
  brand_name: vars.brand_name,
  topic: vars.topic,
  output_dir: vars.output_dir,
  headline: copy.headline_part1 + ' ' + copy.headline_part2,
  caption: copy.caption,
  hashtags: copy.hashtags,
  cover_path: vars.cover_path,
  video_path: vars.video_path,
  slide_paths: vars.slide_paths,
  drive_urls: vars.drive_urls,
  compliance_flags: vars.compliance_summary,
  ads: ads_data,
  generated_at: new Date().toISOString()
};

