// ══════════════════════════════════════════════════════════════════════
// PUBLICAÇÃO AUTOMÁTICA NAS REDES SOCIAIS
// ══════════════════════════════════════════════════════════════════════
// Este node prepara os dados para os nodes de publicação.
// Descomente/configure os nodes de rede social que você usa.
//
// Instagram Business API: precisa de Facebook Page + Instagram Business Account
// Facebook Page: precisa de Page Access Token
// LinkedIn: precisa de LinkedIn Marketing API
// Twitter/X: precisa de API v2 Bearer Token
// ══════════════════════════════════════════════════════════════════════

const data = $('Montar resposta final').item.json;

const post = {
  // Texto da publicação
  caption: data.caption + '\n\n' + (data.hashtags || []).join(' '),
  // Imagem principal (capa do carrossel)
  image_path: data.cover_path,
  // Vídeo (para Reels/Stories)
  video_path: data.video_path,
  // Carousel slides (para Instagram Carousel)
  slide_paths: data.slide_paths || [],
  // Metadados
  brand: data.brand_name,
  topic: data.topic,
  headline: data.headline,
};

return post;

// ══════════════════════════════════════════════════════════════════════
// PLACEHOLDER — INSTAGRAM BUSINESS API
// ══════════════════════════════════════════════════════════════════════
// Para ativar a publicação automática no Instagram:
//
// 1. Crie um app no Meta Business: https://developers.facebook.com
// 2. Vincule sua Page + Instagram Business Account
// 3. Gere um Page Access Token com permissões:
//    - instagram_basic
//    - instagram_content_publish
//    - pages_read_engagement
// 4. Substitua este Code node por um HTTP Request node:
//
//    POST https://graph.facebook.com/v19.0/{ig-user-id}/media
//    Body: {
//      image_url: <URL pública da imagem>,
//      caption: $json.caption,
//      access_token: <PAGE_ACCESS_TOKEN>
//    }
//
//    Depois:
//    POST https://graph.facebook.com/v19.0/{ig-user-id}/media_publish
//    Body: { creation_id: <id do passo anterior>, access_token: ... }
//
// IMPORTANTE: O Instagram API exige que a imagem esteja em URL pública.
// Use o Google Drive ou um bucket S3/R2 como CDN intermediário.
// ══════════════════════════════════════════════════════════════════════

return {
  platform: 'instagram',
  status: 'placeholder',
  message: 'Configure o Instagram Business API para publicação automática.',
  caption: $json.caption,
  image: $json.image_path,
};

// ══════════════════════════════════════════════════════════════════════
// PLACEHOLDER — FACEBOOK PAGE API
// ══════════════════════════════════════════════════════════════════════
// POST https://graph.facebook.com/v19.0/{page-id}/photos
// Body: { url: <URL pública>, message: $json.caption, access_token: ... }
//
// Para vídeo:
// POST https://graph.facebook.com/v19.0/{page-id}/videos
// Body: { file_url: <URL>, description: $json.caption, access_token: ... }
// ══════════════════════════════════════════════════════════════════════

return {
  platform: 'facebook',
  status: 'placeholder',
  message: 'Configure o Facebook Page API.',
};

// ══════════════════════════════════════════════════════════════════════
// LOG DE EXECUÇÃO — salva histórico de tudo que foi gerado
// ══════════════════════════════════════════════════════════════════════
const data = $('Montar resposta final').item.json;

return {
  log: {
    timestamp: data.generated_at,
    brand: data.brand,
    topic: data.topic,
    headline: data.headline,
    has_carousel: (data.slide_paths ?? []).length > 0,
    has_video: !!data.video_path,
    has_ads: !!data.ads?.report_path,
    compliance_flags: data.compliance_flags || '',
    drive_urls: data.drive_urls || [],
  }
};
